def save_preferences(preferences: UserPreferences, filepath: Union[str, Path]) -> None:
    """
    Save user preferences to a JSON file.
    
    Args:
        preferences: UserPreferences object to save
        filepath: Path to the file where preferences will be saved
    """
    filepath = Path(filepath)
    filepath.parent.mkdir(parents=True, exist_ok=True)
    
    data = preferences.to_dict()
    
    temp_filepath = filepath.with_suffix('.tmp')
    try:
        with open(temp_filepath, 'w', encoding='utf-8') as f:
            json.dump(data, f, indent=2, ensure_ascii=False)
        
        temp_filepath.replace(filepath)
    except Exception as e:
        if temp_filepath.exists():
            temp_filepath.unlink()
        raise IOError(f"Failed to save preferences: {e}")


def load_preferences(filepath: Union[str, Path]) -> UserPreferences:
    """
    Load user preferences from a JSON file.
    
    Args:
        filepath: Path to the file containing preferences
        
    Returns:
        UserPreferences object loaded from file
        
    Raises:
        FileNotFoundError: If the file doesn't exist
        ValueError: If the file contains invalid data
    """
    filepath = Path(filepath)
    
    if not filepath.exists():
        raise FileNotFoundError(f"Preferences file not found: {filepath}")
    
    try:
        with open(filepath, 'r', encoding='utf-8') as f:
            data = json.load(f)
        
        if not isinstance(data, dict):
            raise ValueError("Invalid preferences file format")
        
        return UserPreferences.from_dict(data)
    
    except json.JSONDecodeError as e:
        raise ValueError(f"Invalid JSON in preferences file: {e}")
    except Exception as e:
        raise IOError(f"Failed to load preferences: {e}")


